// Get all events
const events = $items("Event Calendar2").map(item => item.json);

// Get all sponsors
const sponsors = $items("Sponsor List2").map(item => item.json);

// Normalize helper
function normalize(str) {
  return (str || "").toString().trim();
}

const output = [];

for (const event of events) {

  const eventId = normalize(event["Event ID"]);
  let sponsorCount = 0;

  for (const sponsor of sponsors) {

    const participatingRaw = sponsor["Event Participating In"] || "";

    const sponsorEventIds = participatingRaw
      .split(",")
      .map(id => normalize(id))
      .filter(id => id.length > 0);

    if (sponsorEventIds.includes(eventId)) {
      sponsorCount++;
    }
  }

  // ✅ Only include events with less than 3 sponsors
  if (sponsorCount < 3) {
    output.push({
      json: {
        eventId: event["Event ID"],
        eventName: event["Event Name"],
        eventDate: event["Event Date"],
        sponsorCount
      }
    });
  }
}

return output;

const events = $items("Events with open slots2");

// Use dynamic today date (recommended)
const today = new Date();
today.setHours(0,0,0,0);

function normalizeDate(d) {
  const date = new Date(d);
  date.setHours(0,0,0,0);
  return date;
}

const output = [];

for (const item of events) {
  const event = item.json;

  const eventDate = normalizeDate(event.eventDate);

  if (eventDate > today) {
    output.push(item);
  }
}

return output;

